module.render:
const columns = Math.max(1, Math.min(6, parseInt(args.columns, 10) || 3));
const gap = args.gap || '1rem';
const style = String(args.cardstyle || 'card').toLowerCase();
const styleClass = style === 'plain' ? ' mdp-grid-plain' : style === 'outline' ? ' mdp-grid-outline' : '';
const align = String(args.align || 'left').toLowerCase();
const pad = (args.padding && String(args.padding).trim()) || '14px 16px';
const radius = (args.radius && String(args.radius).trim()) || 'var(--radius-sm, 8px)';
let html = `\n\n<div class="mdp-mod-grid${styleClass}" style="grid-template-columns: repeat(${columns}, minmax(0, 1fr)); gap: ${gap}; text-align: ${align}; --grid-pad: ${pad}; --grid-radius: ${radius};">\n`;
sections.forEach((section) => {
  const contentStr = section.trim();
  if (!contentStr) return;
  html += `<div class="mdp-mod-grid-card">\n\n${contentStr}\n\n</div>`;
});
html += `</div>\n\n`;
return html;
